dec:
border-collapse: collapse;
  width: 100%;
  font-size: var(--doc-table-text-size);
  line-height: 1.3;
  margin-bottom: 6pt;
  color: var(--doc-primary-color);

border-top: var(--doc-table-border) solid var(--doc-table-border-color);
  border-bottom: var(--doc-table-border) solid var(--doc-table-border-color);
  padding: var(--doc-table-padding);
  text-align: start;
  vertical-align: middle;

display: block;
  font-size: var(--doc-caption-size);
  color: var(--doc-secondary-color);
  margin-top: 4pt;
  margin-bottom: 12pt;
  font-weight: 400;
  text-align: var(--doc-caption-align);
